/**
 * @event 
 * @name acb_odrDtNoGubun_onchange 
 * @description 오더일자 / 오더번호 구분 사용자가 선택 항목을 변경할 경우 발생.
 */
scwin.acb_odrDtNoGubun_onchange = function (info) {

    if (acb_odrDtNoGubun.getValue() == 'NO') {
        udc_odrSt.hide();
        div_qryConKnd2.show('');
    } else {
        udc_odrSt.show('');
        div_qryConKnd2.hide();
    };

};



